import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useEmployees } from '../../hooks/useEmployees';
import employeeService from '../../services/employeeService';
import shiftService from '../../services/shiftService';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import Badge from '../../components/common/Badge';
import Modal from '../../components/common/Modal';
import Input, { Select } from '../../components/common/Input';
import Spinner from '../../components/common/Spinner';
import Alert from '../../components/common/Alert';
import { formatDate, formatCurrency, getInitials } from '../../utils/formatters';
import { ROLES, PAGINATION_LIMIT } from '../../constants';
import './EmployeesPage.css';

const ROLE_LABELS = { admin: 'Admin', manager: 'Manager', employee: 'Angajat' };
const STATUS_LABELS = { active: 'Activ', inactive: 'Inactiv', suspended: 'Suspendat' };

const emptyForm = {
  firstName: '', lastName: '', email: '', role: 'employee',
  position: '', phone: '', baseSalary: '', hireDate: '',
  departmentId: '', shiftId: '', annualLeaveBalance: 21,
};

export default function EmployeesPage() {
  const { isAdminOrManager } = useAuth();
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const [roleFilter, setRoleFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');

  const { employees, total, totalPages, loading, error, refetch } = useEmployees({
    page, limit: PAGINATION_LIMIT, search, role: roleFilter, status: statusFilter,
  });

  const [shifts, setShifts] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editTarget, setEditTarget] = useState(null);
  const [form, setForm] = useState(emptyForm);
  const [saving, setSaving] = useState(false);
  const [formError, setFormError] = useState('');
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    shiftService.getAll().then(r => setShifts(r.data?.data || r.data || [])).catch(() => {});
  }, []);

  const openCreate = () => {
    setEditTarget(null);
    setForm(emptyForm);
    setFormError('');
    setShowModal(true);
  };

  const openEdit = (emp) => {
    setEditTarget(emp);
    setForm({
      firstName: emp.firstName || '',
      lastName: emp.lastName || '',
      email: emp.email || '',
      role: emp.role || 'employee',
      position: emp.position || '',
      phone: emp.phone || '',
      baseSalary: emp.baseSalary || '',
      hireDate: emp.hireDate ? emp.hireDate.slice(0, 10) : '',
      departmentId: emp.departmentId || '',
      shiftId: emp.shiftId || '',
      annualLeaveBalance: emp.annualLeaveBalance ?? 21,
    });
    setFormError('');
    setShowModal(true);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleSave = async () => {
    if (!form.firstName || !form.lastName || !form.email) {
      return setFormError('Prenume, nume și email sunt obligatorii.');
    }
    setSaving(true);
    setFormError('');
    try {
      if (editTarget) {
        await employeeService.update(editTarget.id, form);
      } else {
        await employeeService.create(form);
      }
      setShowModal(false);
      refetch();
    } catch (err) {
      setFormError(err.response?.data?.message || 'Eroare la salvare.');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!deleteTarget) return;
    setDeleting(true);
    try {
      await employeeService.delete(deleteTarget.id);
      setDeleteTarget(null);
      refetch();
    } catch {
      /* ignore */
    } finally {
      setDeleting(false);
    }
  };

  const roleOptions = [
    { value: '', label: 'Toate rolurile' },
    { value: 'admin', label: 'Admin' },
    { value: 'manager', label: 'Manager' },
    { value: 'employee', label: 'Angajat' },
  ];

  const statusOptions = [
    { value: '', label: 'Toate statusurile' },
    { value: 'active', label: 'Activ' },
    { value: 'inactive', label: 'Inactiv' },
    { value: 'suspended', label: 'Suspendat' },
  ];

  const shiftOptions = [
    { value: '', label: '— Fără tură —' },
    ...shifts.map(s => ({ value: s.id, label: s.name })),
  ];

  return (
    <div className="employees-page">
      <div className="employees-header">
        <div>
          <h1>Angajați</h1>
          <p className="text-muted">{total} angajat{total !== 1 ? 'i' : ''} total</p>
        </div>
        {isAdminOrManager && (
          <Button variant="primary" onClick={openCreate}>+ Adaugă angajat</Button>
        )}
      </div>

      <Card>
        <Card.Body>
          <div className="employees-filters">
            <Input
              placeholder="Caută după nume sau email..."
              value={search}
              onChange={e => { setSearch(e.target.value); setPage(1); }}
              icon={<span>🔍</span>}
            />
            <Select
              value={roleFilter}
              onChange={e => { setRoleFilter(e.target.value); setPage(1); }}
              options={roleOptions}
            />
            <Select
              value={statusFilter}
              onChange={e => { setStatusFilter(e.target.value); setPage(1); }}
              options={statusOptions}
            />
          </div>
        </Card.Body>
      </Card>

      <Card>
        {loading ? (
          <div className="employees-loading"><Spinner /></div>
        ) : error ? (
          <Card.Body><Alert type="danger">{error}</Alert></Card.Body>
        ) : employees.length === 0 ? (
          <Card.Body className="text-center text-muted p-2">Niciun angajat găsit.</Card.Body>
        ) : (
          <div className="employees-table-wrapper">
            <table className="employees-table">
              <thead>
                <tr>
                  <th>Angajat</th>
                  <th>Rol</th>
                  <th>Poziție</th>
                  <th>Salariu bază</th>
                  <th>Data angajării</th>
                  <th>Status</th>
                  {isAdminOrManager && <th>Acțiuni</th>}
                </tr>
              </thead>
              <tbody>
                {employees.map(emp => (
                  <tr key={emp.id}>
                    <td>
                      <div className="employee-cell">
                        <div className="employee-avatar">{getInitials(emp.firstName, emp.lastName)}</div>
                        <div>
                          <div className="employee-name">{emp.firstName} {emp.lastName}</div>
                          <div className="employee-email">{emp.email}</div>
                        </div>
                      </div>
                    </td>
                    <td><Badge color={emp.role === 'admin' ? 'danger' : emp.role === 'manager' ? 'warning' : 'info'}>{ROLE_LABELS[emp.role]}</Badge></td>
                    <td>{emp.position || '—'}</td>
                    <td>{emp.baseSalary ? formatCurrency(emp.baseSalary) : '—'}</td>
                    <td>{emp.hireDate ? formatDate(emp.hireDate) : '—'}</td>
                    <td>
                      <Badge color={emp.status === 'active' ? 'success' : emp.status === 'suspended' ? 'danger' : 'default'}>
                        {STATUS_LABELS[emp.status] || emp.status}
                      </Badge>
                    </td>
                    {isAdminOrManager && (
                      <td>
                        <div className="action-buttons">
                          <Button variant="ghost" size="sm" onClick={() => openEdit(emp)}>Editează</Button>
                          <Button variant="danger" size="sm" onClick={() => setDeleteTarget(emp)}>Șterge</Button>
                        </div>
                      </td>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </Card>

      {totalPages > 1 && (
        <div className="pagination">
          <Button variant="secondary" size="sm" disabled={page <= 1} onClick={() => setPage(p => p - 1)}>‹ Anterior</Button>
          <span className="page-info">Pagina {page} din {totalPages}</span>
          <Button variant="secondary" size="sm" disabled={page >= totalPages} onClick={() => setPage(p => p + 1)}>Următor ›</Button>
        </div>
      )}

      {/* Create / Edit Modal */}
      <Modal
        isOpen={showModal}
        onClose={() => setShowModal(false)}
        title={editTarget ? 'Editează angajat' : 'Adaugă angajat nou'}
        size="lg"
        footer={
          <>
            <Button variant="secondary" onClick={() => setShowModal(false)}>Anulează</Button>
            <Button variant="primary" loading={saving} onClick={handleSave}>
              {editTarget ? 'Salvează' : 'Adaugă'}
            </Button>
          </>
        }
      >
        {formError && <Alert type="danger" className="mb-4">{formError}</Alert>}
        <div className="emp-form-grid">
          <Input label="Prenume *" name="firstName" value={form.firstName} onChange={handleChange} />
          <Input label="Nume *" name="lastName" value={form.lastName} onChange={handleChange} />
          <Input label="Email *" name="email" type="email" value={form.email} onChange={handleChange} disabled={!!editTarget} />
          <Input label="Telefon" name="phone" value={form.phone} onChange={handleChange} />
          <Input label="Poziție" name="position" value={form.position} onChange={handleChange} />
          <Select
            label="Rol"
            name="role"
            value={form.role}
            onChange={handleChange}
            options={[
              { value: 'employee', label: 'Angajat' },
              { value: 'manager', label: 'Manager' },
              { value: 'admin', label: 'Admin' },
            ]}
          />
          <Input label="Salariu bază (RON)" name="baseSalary" type="number" value={form.baseSalary} onChange={handleChange} />
          <Input label="Data angajării" name="hireDate" type="date" value={form.hireDate} onChange={handleChange} />
          <Select
            label="Tură asignată"
            name="shiftId"
            value={form.shiftId}
            onChange={handleChange}
            options={shiftOptions}
          />
          <Input label="Zile concediu anual" name="annualLeaveBalance" type="number" value={form.annualLeaveBalance} onChange={handleChange} />
        </div>
      </Modal>

      {/* Delete Confirmation */}
      <Modal
        isOpen={!!deleteTarget}
        onClose={() => setDeleteTarget(null)}
        title="Confirmare ștergere"
        size="sm"
        footer={
          <>
            <Button variant="secondary" onClick={() => setDeleteTarget(null)}>Anulează</Button>
            <Button variant="danger" loading={deleting} onClick={handleDelete}>Șterge</Button>
          </>
        }
      >
        <p>Ești sigur că vrei să ștergi angajatul <strong>{deleteTarget?.firstName} {deleteTarget?.lastName}</strong>? Acțiunea nu poate fi anulată.</p>
      </Modal>
    </div>
  );
}
